import heapq

def merge_sorted_lists(*lists):
    merged = []
    for lst in lists:
        heapq.heappush(merged, lst)
    return heapq.merge(merged)

# Test cases
assert merge_sorted_lists([25, 24, 15, 4, 5, 29, 110],[19, 20, 11, 56, 25, 233, 154],[24, 26, 54, 48]) == [4, 5, 11, 15, 19, 20, 24, 24, 25, 25, 26, 29, 48, 54, 56, 110, 154, 233]
